import 'dart:convert'; import 'dart:io'; import 'package:path/path.dart' as p;
class ExtensionManifest { const ExtensionManifest({required this.id,required this.name,required this.version,this.commands=const[],this.directory}); final String id,name,version; final List<ExtensionCommand> commands; final String? directory; factory ExtensionManifest.fromJson(Map<String,dynamic> j,{String? directory})=>ExtensionManifest(id:j['id']as String???'x',name:j['name']as String???'Ext',version:j['version']as String???'0',commands:(j['commands']as List???[]).whereType<Map>().map((e)=>ExtensionCommand.fromJson(e.cast<String,dynamic>())).toList(),directory:directory); }
class ExtensionCommand { const ExtensionCommand({required this.id,required this.label,this.hint,this.action}); final String id,label; final String? hint,action; factory ExtensionCommand.fromJson(Map<String,dynamic> j)=>ExtensionCommand(id:j['id']as String???'',label:j['label']as String???'',hint:j['hint']as String?,action:j['action']as String?); String paletteId(String e)=> 'ext:$e:$id'; }
class ExtensionLoader { static Directory extensionsDir()=>Directory(p.join(Platform.environment['HOME']??'','.config','krom','extensions')); static Future<List<ExtensionManifest>> loadAll() async { final d=extensionsDir(); if(!d.existsSync())return[]; final o=<ExtensionManifest>[]; for(final e in d.listSync()){if(e is!Directory)continue; final f=File(p.join(e.path,'manifest.json')); if(!f.existsSync())continue; try{o.add(ExtensionManifest.fromJson(jsonDecode(f.readAsStringSync())as Map<String,dynamic>,directory:e.path));}catch(_){}} return o;} static Future<void> runCommandAction(ExtensionManifest m,ExtensionCommand c) async { final a=c.action,dir=m.directory; if(a==null||dir==null)return; final parts=a.trim().split(RegExp(r'\s+')); if(parts.isEmpty)return; await Process.start(parts.first,parts.skip(1).toList(),workingDirectory:dir,mode:ProcessStartMode.detached);} }
